  if (cashbackPc == 0.2) {
    tier = 'Medium';
  } else if (cashbackPc > 0.2) {
    tier = 'High';
  }
  products.forEach(function (product) {
    var p = product;
    var margin = product.margin;
    var origPrice = parseInt(product.price, 10) * 1.2;
    var price = origPrice;
    var offAmount = 0;
    var savingsPc = 0;
    var marginPc = applyMarginProtection(margin, tier);
    var cashbackAmount = cashbackPc * 300;
    var discountedAmount = marginPc * price;
